Write a table-driven test that asserts both the value and the error message substring for this function:

```go
// Sqrt returns the square root of x, or an error for negatives.
func Sqrt(x float64) (float64, error) {
	if x < 0 {
		return 0, fmt.Errorf("Sqrt: negative input %g", x)
	}
	return math.Sqrt(x), nil
}
```

response:
```go
func TestSqrt(t *testing.T) {
	tests := []struct {
		name       string
		in         float64
		want       float64
		wantErrSub string // empty = expect no error
	}{
		{"perfect square", 9, 3, ""},
		{"zero", 0, 0, ""},
		{"two", 2, math.Sqrt2, ""},
		{"negative", -4, 0, "negative input"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := Sqrt(tt.in)
			if tt.wantErrSub != "" {
				if err == nil || !strings.Contains(err.Error(), tt.wantErrSub) {
					t.Fatalf("err = %v, want containing %q", err, tt.wantErrSub)
				}
				return
