	tests := []struct {
		name   string
		animal Animal
		want   string
	}{
		{"dog", Dog{}, "Woof"},
		{"cat", Cat{}, "Meow"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
